// Global map storage
std::map<std::string, std::vector<std::vector<int>>> g_allMaps;

// Parse tile data from string
std::vector<std::vector<int>> parseTileData(const std::string& data) {
    std::vector<std::vector<int>> result;
    std::stringstream ss(data);
    std::string line;
    
    while (std::getline(ss, line, ';')) {
        std::vector<int> row;
        std::stringstream line_ss(line);
        std::string cell;
        
        while (std::getline(line_ss, cell, ',')) {
            row.push_back(std::stoi(cell));
        }
        
        if (!row.empty()) {
            result.push_back(row);
        }
    }
    
    return result;
}

